#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
int main() {
    int N, M, C;
    scanf("%d %d %d", &N, &M, &C);
    int* upper = (int*)malloc(N * sizeof(int));
    int* lower = (int*)malloc(M * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &upper[i]);
    }
    for (int i = 0; i < M; i++) {
        scanf("%d", &lower[i]);
    }
    int* countUpper = (int*)calloc(C + 1, sizeof(int));
    int* countLower = (int*)calloc(C + 1, sizeof(int));
    for (int i = 0; i < N; i++) {
        countUpper[upper[i]]++;
    }
    for (int i = 0; i < M; i++) {
        countLower[lower[i]]++;
    }
    int* dp = (int*)calloc(C + 1, sizeof(int));
    for (int i = 1; i <= C; i++) {
        dp[i] = (long long)countUpper[i] * countLower[i] % MOD;
    }
    for (int i = 2; i <= C; i++) {
        for (int j = 1; j < i; j++) {
            dp[i] = (dp[i] + (long long)dp[j] * countUpper[i] % MOD * countLower[i] % MOD) % MOD;
        }
    }
    for (int i = 1; i <= C; i++) {
        printf("%d ", dp[i]);
    }
    return 0;
}

