import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt(), M = sc.nextInt(), C = sc.nextInt();
        int[] upper = new int[N], lower = new int[M];
        for (int i = 0; i < N; i++) {
            upper[i] = sc.nextInt();
        }
        for (int i = 0; i < M; i++) {
            lower[i] = sc.nextInt();
        }
        int[] countUpper = new int[C + 1], countLower = new int[C + 1];
        for (int i = 0; i < N; i++) {
            countUpper[upper[i]]++;
        }
        for (int i = 0; i < M; i++) {
            countLower[lower[i]]++;
        }
        int[] dp = new int[C + 1];
        final int MOD = 1000000007;
        for (int i = 1; i <= C; i++) {
            dp[i] = (int)((long)countUpper[i] * countLower[i] % MOD);
        }
        for (int i = 2; i <= C; i++) {
            for (int j = 1; j < i; j++) {
                dp[i] = (dp[i] + (int)((long)dp[j] * countUpper[i] % MOD * countLower[i] % MOD)) % MOD;
            }
        }
        for (int i = 1; i <= C; i++) {
            System.out.print(dp[i] + " ");
        }
    }
}

