const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function nextLine() {
    return input[idx++];
}
function nextInts() {
    return nextLine().split(' ').map(x => parseInt(x));
}
const [N, M, C] = nextInts();
const upper = nextInts();
const lower = nextInts();
const countUpper = new Array(C + 1).fill(0);
const countLower = new Array(C + 1).fill(0);
for (let i = 0; i < N; i++) {
    countUpper[upper[i]]++;
}
for (let i = 0; i < M; i++) {
    countLower[lower[i]]++;
}
const dp = new Array(C + 1).fill(0);
const MOD = 1000000007;
for (let i = 1; i <= C; i++) {
    dp[i] = (countUpper[i] * countLower[i]) % MOD;
}
for (let i = 2; i <= C; i++) {
    for (let j = 1; j < i; j++) {
        dp[i] = (dp[i] + (dp[j] * countUpper[i] % MOD * countLower[i] % MOD)) % MOD;
    }
}
